// // This module implements a 16-bit shift register that shifts right on a falling clock edge when the shift_enable signal is high. If shift_enable is low, the register should hold its value. The register should also have a reset signal that initializes it to all ones.
module shift_register (  
    input clk,  
    input reset,  
    input shift_enable,  
    input serial_in,  
    output reg [15:0] parallel_out  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            parallel_out <= 16'b0;  
        else if (shift_enable)  
            parallel_out <= {parallel_out[14:0], serial_in};  
    end  
endmodule
